 5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Param;
 6→
 7→use Eliberty\RedpillBundle\Exception\ApiConfigException;
 8→
 9→/**
10→ * Class ApiClientParameters manage api client parameters.
11→ *
12→ * Initialize http-client with values (uri and data payload) retrieve from ConfigManager.
13→ *
14→ * @method static withOptions(array $options) Returns a new instance of the client with new default options
15→ */
16→class ApiClientParameters implements ApiClientParametersInterface
17→{
18→    /**
19→     * ApiParametersInterface can have (key?:) keys below :
20→     * - uri?: string       (default='' but value begining with "http(s)://" required if base_uri is not set into http-client)
21→     * - options?: array    (default=[]).
22→     */
23→    private ?ApiParametersInterface $apiParameters;
24→
25→    public function __construct(?ApiParametersInterface $apiParameters = null)
26→    {
27→        $this->apiParameters = $apiParameters;
28→    }
29→
30→    /**
31→     * @return array<string, mixed>
32→     */
33→    public function getParameters(): array
34→    {
35→        return null === $this->apiParameters ? [] : $this->apiParameters->getAll();
36→    }
37→
38→    /**
39→     * @return array|string|float|int|bool|\DateTime|null
40→     */
41→    public function getParameter(string $key)
42→    {
43→        return null === $this->apiParameters ? null : $this->apiParameters->get($key);
44→    }
45→
46→    public function hasParameter(string $key): bool
47→    {
48→        return null === $this->apiParameters ? false : $this->apiParameters->has($key);
49→    }
50→
51→    public function getStringParameter(string $key, bool $throwError = false): ?string
52→    {
53→        if (null === $this->apiParameters) {
54→            return null;
55→        }
56→
57→        if (\is_string($value = $this->apiParameters->get($key))) {
58→            return $value;
59→        }
60→
61→        if ($throwError) {
62→            throw ApiConfigException::unexpectedParameterValue($key, $value, 'string');
63→        }
64→
65→        return null;
66→    }
67→
68→    public function getArrayParameter(string $key, bool $throwError = false): ?array
69→    {
70→        if (null === $this->apiParameters) {
71→            return null;
72→        }
73→
74→        if (\is_array($value = $this->apiParameters->get($key))) {
75→            return $value;
76→        }
77→
78→        if ($throwError) {
79→            throw ApiConfigException::unexpectedParameterValue($key, $value, 'array');
80→        }
81→
82→        return null;
83→    }
84→}
