  2→
  3→declare(strict_types = 1);
  4→
  5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Client;
  6→
  7→use Eliberty\RedpillBundle\ApiClient\Infra\Error\Token\TokenErrorInterface;
  8→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiClientParameters;
  9→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiParametersInterface;
 10→use Eliberty\RedpillBundle\ApiClient\Infra\Response\ApiResponseErrorInterface;
 11→use Eliberty\RedpillBundle\ApiClient\Infra\Response\ApiResponseInterface;
 12→use Eliberty\RedpillBundle\ApiClient\Infra\Token\ApiTokenInterface;
 13→use Eliberty\RedpillBundle\Exception\ApiClientException;
 14→use Eliberty\RedpillBundle\Exception\ApiRetryableException;
 15→use Eliberty\RedpillBundle\Exception\ApiTokenException;
 16→use Eliberty\RedpillBundle\Webinstance\IdentityService;
 17→use Psr\Log\LoggerInterface;
 18→use Symfony\Component\HttpClient\Exception\InvalidArgumentException;
 19→use Symfony\Component\HttpClient\Exception\JsonException;
 20→use Symfony\Contracts\HttpClient\Exception\DecodingExceptionInterface;
 21→use Symfony\Contracts\HttpClient\Exception\RedirectionExceptionInterface;
 22→use Symfony\Contracts\HttpClient\Exception\TransportExceptionInterface;
 23→use Symfony\Contracts\HttpClient\HttpClientInterface;
 24→
 25→/**
 26→ * AuthJwtApiClient is an authenticated api client with token-based authentication.
 27→ *
 28→ * Token-based authentication process :
 29→ *  - if token not found by its discriminant parameters (more or less main_uri and username)
 30→ *  -   first call login to get token (like JWT)
 31→ *  -   store token
 32→ *  - main call is authenticated with stored token
 33→ *  - if invalid/expired token response
 34→ *  -   re-call login to get token
 35→ *  -   store token
 36→ *  -   main call retry
 37→ */
 38→class AuthJwtApiClient extends ApiClientParameters implements ApiClientInterface
 39→{
 40→    protected ApiClientInterface $apiClient;
 41→
 42→    protected ApiTokenInterface $apiToken;
 43→
 44→    protected TokenErrorInterface $tokenError;
 45→
 46→    protected LoggerInterface $logger;
 47→
 48→    protected IdentityService $identityService;
 49→
 50→    /**
 51→     * $apiParameters require (key*:) or can have (key?:) keys below :
 52→     * - base_uri|discriminant_uri*: string ('base_uri' key will be set as 'main_uri' key if it used with $apiConfigParams and discriminant_uri is required if the base_uri already set into http-client)
 53→     * - login_uri*: string
 54→     * - credentials*: array
 55→     * - login_multi_tenant_header_key? string (default='') : if set, the login call will add a header with this key and the value will be the current webinstance shortname or id (if the key end with -id)
 56→     * - main_uri?: string           (default='')
 57→     * - client_auth_key?: string    (default='auth_bearer')
 58→     * - response_token_key?: string (default='token')
 59→     * - login_data_key?: string     (default='json').
 60→     */
 61→    public function __construct(
 62→        HttpClientInterface $client,
 63→        ApiParametersInterface $apiParameters,
 64→        ApiTokenInterface $apiToken,
 65→        TokenErrorInterface $tokenError,
 66→        LoggerInterface $logger,
 67→        IdentityService $identityService
 68→    ) {
 69→        parent::__construct($apiParameters);
 70→        $this->apiClient       = new BaseApiClient($client, $logger);
 71→        $this->apiToken        = $apiToken;
 72→        $this->tokenError      = $tokenError;
 73→        $this->logger          = $logger;
 74→        $this->identityService = $identityService;
 75→    }
 76→
 77→    /**
 78→     * Api main call with auto-login and auto-refresh token.
 79→     *
 80→     * @param array<string, mixed> $options
 81→     *
 82→     * @throws ApiTokenException
 83→     * @throws ApiClientException
 84→     * @throws TransportExceptionInterface
 85→     * @throws RedirectionExceptionInterface 3xx
 86→     * @throws DecodingExceptionInterface
 87→     * @throws InvalidArgumentException
 88→     * @throws JsonException
 89→     */
 90→    public function call(string $method, string $uri = '', array $options = []): ApiResponseInterface
 91→    {
 92→        $this->apiToken->setHashKey($this->getParameters());
 93→        if (!$this->apiToken->hasValidToken()) {
 94→            $this->login();
 95→        }
 96→
 97→        $apiResponse = $this->authenticatedCall($method, $uri, $options);
 98→
 99→        // return data in case of success
100→        if (!$apiResponse instanceof ApiResponseErrorInterface) {
101→            return $apiResponse;
102→        }
103→
104→        $errorMessage = $apiResponse->getErrorMesssage();
105→        if (!$this->tokenError->isInvalidToken($apiResponse)) {
106→            if (500 > $apiResponse->getCode()) {
107→                throw new ApiClientException($errorMessage, $apiResponse->getCode());
108→            }
109→
110→            throw new ApiRetryableException($errorMessage, $apiResponse->getCode());
111→        }
112→
113→        $this->logger->debug(sprintf('New token required ! %s', $errorMessage));
114→        $this->login();
115→
116→        return $this->authenticatedCall($method, $uri, $options);
117→    }
118→
119→    /**
120→     * Api login process with login uri and credentials to get token and save it.
121→     *
122→     * note: loginClient (http-client) base_uri option need to be set as login full uri
123→     *
124→     * @throws TransportExceptionInterface
125→     * @throws RedirectionExceptionInterface 3xx
126→     * @throws DecodingExceptionInterface
127→     * @throws InvalidArgumentException
128→     * @throws JsonException
129→     */
130→    private function login(): void
131→    {
132→        $loginUri                  = $this->getStringParameter('login_uri', true);
133→        $loginMultiTenantHeaderKey = $this->getStringParameter('login_multi_tenant_header_key');
134→        $credentials               = $this->getArrayParameter('credentials', true);
135→        $responseTokenKey          = $this->getStringParameter('response_token_key') ?? 'token';
136→        $loginDataKey              = $this->getStringParameter('login_data_key')     ?? 'json';
137→
138→        $options = [$loginDataKey => $credentials];
139→
140→        if ($loginMultiTenantHeaderKey) {
141→            $headerValue                                    = str_ends_with(strtolower($loginMultiTenantHeaderKey), '-id') ? $this->identityService->getCurrentWebinstance()->getId() : $this->identityService->getCurrentWebinstance()->getShortname();
142→            $options['headers'][$loginMultiTenantHeaderKey] = $headerValue;
143→        }
144→
145→        try {
146→            // Get new Bearer token from api client call
147→            $apiResponse = $this->apiClient->call('POST', $loginUri, $options);
148→        } catch (\Exception $exception) { // catch all exceptions to log api parameters
149→            $this->logger->error($exception->getMessage(), ['apiParams' => $this->getParameters()]);
150→
151→            throw $exception;
152→        }
153→
154→        if (!\is_string($newToken = $apiResponse->getValue($responseTokenKey))) {
155→            $errorMessage = sprintf('Token key [%s] not found into response body', $responseTokenKey);
156→            $this->logger->error($errorMessage, $apiResponse->getData());
157→            throw new ApiTokenException($errorMessage.': '.json_encode($apiResponse->getData()));
158→        }
159→
160→        $this->logger->debug('Token received', [$responseTokenKey => $newToken]);
161→        $this->apiToken->setToken($newToken);
162→    }
163→
164→    /**
165→     * Api client authenticated call.
166→     *
167→     * @param array<string, mixed> $options
168→     *
169→     * @throws TransportExceptionInterface
170→     * @throws RedirectionExceptionInterface 3xx
171→     * @throws DecodingExceptionInterface
172→     * @throws InvalidArgumentException
173→     * @throws JsonException
174→     */
175→    private function authenticatedCall(string $method, string $uri, array $options = []): ApiResponseInterface
176→    {
177→        $callUri = $this->getStringParameter('main_uri') ?? '';
178→        $callUri .= $uri;
179→
180→        if ($optionsParam = $this->getArrayParameter('options')) {
181→            $options = array_merge($optionsParam, $options);
182→        }
183→
184→        $clientTokenOptionKey           = $this->getStringParameter('client_auth_key') ?? 'auth_bearer';
185→        $options[$clientTokenOptionKey] = $this->apiToken->getToken();
186→
187→        try {
188→            $apiResponse = $this->apiClient->call($method, $callUri, $options);
189→        } catch (\Exception $exception) { // catch all exceptions to log api parameters
190→            $this->logger->error($exception->getMessage(), ['apiParams' => $this->getParameters()]);
191→
192→            throw $exception;
193→        }
194→
195→        return $apiResponse;
196→    }
197→}
