 2→
 3→declare(strict_types = 1);
 4→
 5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Token;
 6→
 7→use Eliberty\RedpillBundle\Exception\ApiTokenException;
 8→use Psr\Log\LoggerInterface;
 9→use Psr\SimpleCache\CacheInterface;
10→use Psr\SimpleCache\InvalidArgumentException;
11→
12→/**
13→ * RedisApiToken manage api token with redis cache.
14→ */
15→final class RedisApiToken extends TokenCacheKey implements ApiTokenInterface
16→{
17→    private CacheInterface $cache;
18→
19→    private TokenInterface $token;
20→
21→    private LoggerInterface $logger;
22→
23→    public function __construct(
24→        CacheInterface $redisCache,
25→        TokenInterface $token,
26→        LoggerInterface $logger
27→    ) {
28→        $this->cache  = $redisCache;
29→        $this->token  = $token;
30→        $this->logger = $logger;
31→    }
32→
33→    /**
34→     * Set the token to redis cache with its ttl (the remaining time to live in seconds).
35→     *
36→     * @throws ApiTokenException
37→     */
38→    public function setToken(string $token): self
39→    {
40→        if (null === $this->getHashKey()) {
41→            throw new ApiTokenException('Token hash key need to be set before storing token into redis cache');
42→        }
43→
44→        $ttl = $this->token->set($token)->getTtl();
45→
46→        try {
47→            $this->cache->set($this->getHashKey(), $token, $ttl);
48→        } catch (InvalidArgumentException $e) {
49→            throw new ApiTokenException(sprintf('Invalid token key[%s] or value[%s]', $this->getHashKey(), $token));
50→        }
51→
52→        $this->logger->debug('Token store into redis cache', ['token' => $token]);
53→
54→        return $this;
55→    }
56→
57→    /**
58→     * Get token already set or from redis cache if exists.
59→     *
60→     * @throws ApiTokenException
61→     */
62→    public function getToken(): ?string
63→    {
64→        if (null === $this->getHashKey()) {
65→            throw new ApiTokenException('Token hash key need to be set before accessing token from redis cache');
66→        }
67→
68→        try {
69→            $cachedToken = $this->cache->get($this->getHashKey());
70→        } catch (InvalidArgumentException $e) {
71→            throw new ApiTokenException(sprintf('Invalid token key[%s]', $this->getHashKey()));
72→        }
73→
74→        if (\is_string($cachedToken) && !$this->token->set($cachedToken)->isExpired()) {
75→            $this->logger->debug('Valid token found in cache', ['token' => $cachedToken]);
76→
77→            return $cachedToken;
78→        }
79→
80→        return null;
81→    }
82→
83→    /**
84→     * Is token exist and valid ?
85→     */
86→    public function hasValidToken(): bool
87→    {
88→        return (bool) $this->getToken();
89→    }
90→}
