 5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Token;
 6→
 7→use Eliberty\RedpillBundle\Exception\ApiConfigException;
 8→use Eliberty\RedpillBundle\Util\CacheUtils;
 9→
10→/**
11→ * TokenCacheKey manage token cache key with discriminant values.
12→ */
13→class TokenCacheKey
14→{
15→    /**
16→     * Discriminant elements of the token hash key.
17→     *
18→     * @var string[]
19→     */
20→    private array $discriminantValues = [];
21→
22→    private ?string $hashKey = null;
23→
24→    /**
25→     * Set the Api token unique hash key (used to store and retrieve token) from apiParameters.
26→     *
27→     * @param array<string, mixed> $parameters
28→     */
29→    public function setHashKey(array $parameters): void
30→    {
31→        $apiDiscriminantValues = $this->getDiscriminant($parameters);
32→        if ($this->discriminantValues !== $apiDiscriminantValues) {
33→            $this->discriminantValues = $apiDiscriminantValues;
34→
35→            $this->hashKey = CacheUtils::computeKey($this->discriminantValues);
36→        }
37→    }
38→
39→    /**
40→     * Get the Api token unique hash key (used to store and retrieve token).
41→     */
42→    public function getHashKey(): ?string
43→    {
44→        return $this->hashKey;
45→    }
46→
47→    /**
48→     * Get Api discriminant values from apiParameters:
49→     * - main uri
50→     * - login credentials except password.
51→     *
52→     * @param array<string, mixed> $parameters
53→     *
54→     * @return array<string, mixed>
55→     */
56→    protected function getDiscriminant(array $parameters): array
57→    {
58→        $credentials = $parameters['credentials'] ?? null;
59→        if (\is_array($credentials)) {
60→            $keysExcluded = \is_array($parameters['cache_keys_excluded'] ?? null) ? $parameters['cache_keys_excluded'] : ['password'];
61→            foreach ($credentials as $key => $value) {
62→                if (\in_array($key, $keysExcluded)) {
63→                    continue;
64→                }
65→                $discriminant[$key] = $value;
66→            }
67→        }
68→
69→        $discriminant_uri = $parameters['discriminant_uri'] ?? ($parameters['base_uri'] ?? ($parameters['main_uri'] ?? null));
70→        if (null === $discriminant_uri) {
71→            throw new ApiConfigException('Unable to find api key parameter [discriminant_uri], [base_uri] or [main_uri] for token discriminant');
72→        }
73→
74→        $discriminant['uri'] = $discriminant_uri;
75→
76→        return $discriminant;
77→    }
78→}
