  1→<?php
  2→
  3→declare(strict_types = 1);
  4→
  5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Client;
  6→
  7→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiClientParameters;
  8→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiParametersInterface;
  9→use Eliberty\RedpillBundle\ApiClient\Infra\Response\ApiResponse;
 10→use Eliberty\RedpillBundle\ApiClient\Infra\Response\ApiResponseError;
 11→use Eliberty\RedpillBundle\ApiClient\Infra\Response\ApiResponseInterface;
 12→use Psr\Log\LoggerInterface;
 13→use Symfony\Component\HttpClient\Exception\InvalidArgumentException;
 14→use Symfony\Component\HttpClient\Exception\JsonException;
 15→use Symfony\Contracts\HttpClient\Exception\ClientExceptionInterface;
 16→use Symfony\Contracts\HttpClient\Exception\DecodingExceptionInterface;
 17→use Symfony\Contracts\HttpClient\Exception\RedirectionExceptionInterface;
 18→use Symfony\Contracts\HttpClient\Exception\ServerExceptionInterface;
 19→use Symfony\Contracts\HttpClient\Exception\TransportExceptionInterface;
 20→use Symfony\Contracts\HttpClient\HttpClientInterface;
 21→
 22→/**
 23→ * BaseApiClient call api using http-client and manage 4xx/5xx response code to return useful api errors.
 24→ */
 25→class BaseApiClient extends ApiClientParameters implements ApiClientInterface
 26→{
 27→    protected HttpClientInterface $client;
 28→
 29→    protected LoggerInterface $logger;
 30→
 31→    /**
 32→     * $apiParameters can have (key?:) keys below :
 33→     * - uri?: string       (default='' but value begining with "http(s)://" required if base_uri is not set into http-client)
 34→     * - options?: array    (default=[]).
 35→     */
 36→    public function __construct(
 37→        HttpClientInterface $client,
 38→        LoggerInterface $logger,
 39→        ?ApiParametersInterface $apiParameters = null
 40→    ) {
 41→        parent::__construct($apiParameters);
 42→        $this->client = $client;
 43→        $this->logger = $logger;
 44→    }
 45→
 46→    /**
 47→     * Api client simple call.
 48→     *
 49→     * @param array<string, mixed> $options
 50→     *
 51→     * @throws TransportExceptionInterface
 52→     * @throws RedirectionExceptionInterface 3xx
 53→     * @throws DecodingExceptionInterface
 54→     * @throws InvalidArgumentException
 55→     * @throws JsonException
 56→     */
 57→    public function call(string $method, string $uri = '', array $options = []): ApiResponseInterface
 58→    {
 59→        if ($uriParam = $this->getStringParameter('uri')) {
 60→            $uri = $uriParam.$uri;
 61→        }
 62→
 63→        if ($optionsParam = $this->getArrayParameter('options')) {
 64→            $options = array_merge($optionsParam, $options);
 65→        }
 66→
 67→        $this->logger->debug(sprintf('Api call [%s] %s', $method, $uri), $options);
 68→        // Throw exception on error
 69→        $response   = $this->client->request($method, $uri, $options);
 70→        $statusCode = $response->getStatusCode();
 71→        $calledUrl  = $response->getInfo('url');
 72→
 73→        try {
 74→            $data = $response->toArray();
 75→        } catch (ClientExceptionInterface|ServerExceptionInterface $mainException) { // catch 4xx/5xx errors and let throw other status code
 76→            try {
 77→                // First try to get specific remote api error
 78→                $errorData = $response->toArray(false);
 79→            } catch (JsonException $exception) {
 80→                // If no specific remote api error returned, get main exception error
 81→                $errorData['error'] = $mainException->getMessage();
 82→                $errorData['info']  = $response->getInfo('error');   // Not returned as expected
 83→            }
 84→
 85→            // Return Api response error
 86→            return new ApiResponseError($statusCode, $errorData, $calledUrl);
 87→        } catch (\Exception $exception) { // catch all other exceptions
 88→            if ($apiParams = $this->getParameters()) {  // just to log api parameters if set
 89→                $this->logger->error($exception->getMessage(), ['apiParams' => $apiParams]);
 90→            }
 91→
 92→            throw $exception;
 93→        }
 94→
 95→        $this->logger->info(
 96→            sprintf(
 97→                'Api call success [%d] with %d item%s on %s',
 98→                $statusCode,
 99→                \count($data),
100→                \count($data) > 1 ? 's' : '',
101→                $calledUrl
102→            )
103→        );
104→
105→        return new ApiResponse($statusCode, $data, $calledUrl);
106→    }
107→}
