  6→
  7→use Eliberty\ConfigManagerBundle\Model\ConfigManager;
  8→use Eliberty\RedpillBundle\ApiClient\Infra\Error\Token\TokenErrorInterface;
  9→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiConfigParameters;
 10→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiParameters;
 11→use Eliberty\RedpillBundle\ApiClient\Infra\Param\ApiParametersInterface;
 12→use Eliberty\RedpillBundle\ApiClient\Infra\Token\ApiTokenInterface;
 13→use Eliberty\RedpillBundle\Webinstance\IdentityService;
 14→use Psr\Log\LoggerInterface;
 15→use Symfony\Component\HttpClient\CurlHttpClient;
 16→use Symfony\Contracts\HttpClient\HttpClientInterface;
 17→
 18→/**
 19→ * ParameterizedClientFactory create client with parameters from various origins (eg: ConfigManager) to request api.
 20→ */
 21→class ParameterizedClientFactory
 22→{
 23→    private ConfigManager $cfgmanager;
 24→    private IdentityService $identityService;
 25→    protected LoggerInterface $logger;
 26→
 27→    public function __construct(
 28→        ConfigManager $cfgmanager,
 29→        IdentityService $identityService,
 30→        LoggerInterface $logger
 31→    ) {
 32→        $this->cfgmanager      = $cfgmanager;
 33→        $this->identityService = $identityService;
 34→        $this->logger          = $logger;
 35→    }
 36→
 37→    /**
 38→     * @param array<string, mixed>                        $apiParams
 39→     * @param array<string, array{0: string, 1?: string}> $apiConfigParams (paramKey => [ConfigManagerKey, ?JsonValueKey])
 40→     */
 41→    public function createBaseHttpClient(
 42→        HttpClientInterface $client,
 43→        array $apiParams = [],
 44→        array $apiConfigParams = []
 45→    ): BaseHttpClient {
 46→        $apiParameters = $this->createApiParameters($apiParams, $apiConfigParams);
 47→        $client        = $this->getDefaultOrCreateNewHttpClient($client, $apiParameters);
 48→
 49→        return new BaseHttpClient($client, $apiParameters);
 50→    }
 51→
 52→    /**
 53→     * @param array<string, mixed>                        $apiParams
 54→     * @param array<string, array{0: string, 1?: string}> $apiConfigParams (paramKey => [ConfigManagerKey, ?JsonValueKey])
 55→     */
 56→    public function createBaseApiClient(
 57→        HttpClientInterface $client,
 58→        array $apiParams = [],
 59→        array $apiConfigParams = []
 60→    ): BaseApiClient {
 61→        $apiParameters = $this->createApiParameters($apiParams, $apiConfigParams);
 62→        $client        = $this->getDefaultOrCreateNewHttpClient($client, $apiParameters);
 63→
 64→        return new BaseApiClient($client, $this->logger, $apiParameters);
 65→    }
 66→
 67→    /**
 68→     * @param array<string, mixed>                        $apiParams
 69→     * @param array<string, array{0: string, 1?: string}> $apiConfigParams (paramKey => [ConfigManagerKey, ?JsonValueKey])
 70→     */
 71→    public function createAuthJwtApiClient(
 72→        HttpClientInterface $client,
 73→        ApiTokenInterface $apiToken,
 74→        TokenErrorInterface $tokenError,
 75→        array $apiParams = [],
 76→        array $apiConfigParams = []
 77→    ): AuthJwtApiClient {
 78→        $apiParameters = $this->createApiParameters($apiParams, $apiConfigParams);
 79→        $client        = $this->getDefaultOrCreateNewHttpClient($client, $apiParameters);
 80→
 81→        return new AuthJwtApiClient($client, $apiParameters, $apiToken, $tokenError, $this->logger, $this->identityService);
 82→    }
 83→
 84→    /**
 85→     * @param array<string, mixed>                        $apiParams
 86→     * @param array<string, array{0: string, 1?: string}> $apiConfigParams (paramKey => [ConfigManagerKey, ?JsonValueKey])
 87→     */
 88→    private function createApiParameters(array $apiParams, array $apiConfigParams): ApiParametersInterface
 89→    {
 90→        $apiParameters = new ApiParameters($apiParams);
 91→        if ($apiConfigParams) {
 92→            $apiParameters = new ApiConfigParameters($this->cfgmanager, $apiParameters, $apiConfigParams);
 93→        }
 94→
 95→        return $apiParameters;
 96→    }
 97→
 98→    private function getDefaultOrCreateNewHttpClient(HttpClientInterface $client, ApiParametersInterface $apiParameters): HttpClientInterface
 99→    {
100→        $defaultOptions = $apiParameters->get('client_options');
101→        if (!\is_array($defaultOptions)) {
102→            $defaultOptions = [];
103→        }
104→
105→        $baseUri = $apiParameters->get('base_uri');
106→        if (\is_string($baseUri) && !empty($baseUri)) {
107→            $defaultOptions['base_uri'] = $baseUri;
108→        }
109→
110→        return $defaultOptions ? new CurlHttpClient($defaultOptions) : $client;
111→    }
112→}
