  1→<?php
  2→
  3→declare(strict_types = 1);
  4→
  5→namespace Eliberty\RedpillBundle\ApiClient\Ingenie;
  6→
  7→use Doctrine\ORM\EntityManagerInterface;
  8→use Eliberty\RedpillBundle\ApiClient\Ingenie\Repository\IngenieApiRepository;
  9→use Eliberty\RedpillBundle\Entity\Contact;
 10→use Eliberty\RedpillBundle\Exception\ApiClientException;
 11→use Eliberty\RedpillBundle\Exception\IngenieException;
 12→use Psr\Log\LoggerInterface;
 13→
 14→/**
 15→ * Class IngenieService
 16→ * This class permit to process a contact by Ingenie Customer API.
 17→ */
 18→class IngenieService
 19→{
 20→    private const INGENIE_CONTACT_DATA_CUSTOM_KEY = 'ingenie.customer.id';
 21→
 22→    private IngenieConfig $ingenieConfig;
 23→    private IngenieResourceSpecification $ingenieResourceSpecification;
 24→    private IngenieApiRepository $ingenieApiRepository;
 25→    private IngenieCustomerBuilder $ingenieCustomerBuilder;
 26→    private EntityManagerInterface $entityManager;
 27→    private LoggerInterface $logger;
 28→
 29→    public function __construct(
 30→        IngenieConfig $ingenieConfig,
 31→        IngenieResourceSpecification $ingenieResourceSpecification,
 32→        IngenieApiRepository $ingenieApiRepository,
 33→        IngenieCustomerBuilder $ingenieCustomerBuilder,
 34→        EntityManagerInterface $entityManager,
 35→        LoggerInterface $logger
 36→    ) {
 37→        $this->ingenieConfig                = $ingenieConfig;
 38→        $this->ingenieResourceSpecification = $ingenieResourceSpecification;
 39→        $this->ingenieApiRepository         = $ingenieApiRepository;
 40→        $this->ingenieCustomerBuilder       = $ingenieCustomerBuilder;
 41→        $this->entityManager                = $entityManager;
 42→        $this->logger                       = $logger;
 43→    }
 44→
 45→    /**
 46→     * Get contact able to be processed by Ingenie Customer Api,
 47→     * on every address, user or contact change (inserted or updated).
 48→     *
 49→     * @param array<string, array<int, mixed>> $changeSet
 50→     *
 51→     * @throws IngenieException
 52→     */
 53→    public function getProcessableContact(string $entityClassName, int $entityId, string $method, array $changeSet): ?Contact
 54→    {
 55→        if (
 56→            !$this->ingenieConfig->isApiEnabled()
 57→            || !\in_array($method, ['PERSIST', 'UPDATE'])
 58→            || !\in_array($entityClassName, array_keys(IngenieResourceSpecification::DB_FIELDS_WATCHED))
 59→            || ($changeSet && !$this->ingenieResourceSpecification->hasFieldToSync($entityClassName, $changeSet))
 60→            || (null === $entity = $this->fetchResource($entityId, $entityClassName))
 61→            || !$this->ingenieResourceSpecification->isSatisfiedBy($entity)
 62→        ) {
 63→            return null;
 64→        }
 65→
 66→        return $this->ingenieResourceSpecification->getContact($entity);
 67→    }
 68→
 69→    /**
 70→     * @param class-string $entityClassName
 71→     *
 72→     * @throws IngenieException
 73→     */
 74→    private function fetchResource(int $entityId, string $entityClassName = Contact::class): ?object
 75→    {
 76→        $entity = $this->entityManager->getRepository($entityClassName)->find($entityId);
 77→
 78→        if (null === $entity) {
 79→            return null;
 80→        }
 81→
 82→        // To get always fresh data
 83→        $this->entityManager->refresh($entity);
 84→
 85→        return $entity;
 86→    }
 87→
 88→    /**
 89→     * Fetch contact by Id and send it to Ingenie Api customer.
 90→     *
 91→     * @throws IngenieException
 92→     */
 93→    public function processContactById(int $contactId): bool
 94→    {
 95→        $contact = $this->fetchResource($contactId);
 96→
 97→        return $this->processContact($contact);
 98→    }
 99→
100→    /**
101→     * Send create or update contact to Ingenie Api customer.
102→     *
103→     * @throws IngenieException
104→     */
105→    public function processContact(Contact $contact): bool
106→    {
107→        // Get Ingenie Customer Id, if contact already sent
108→        $ingenieCustomerId = $this->getIngenieCustomerId($contact);
109→
110→        // Create IngenieCustomer object from Redpill Contact entity
111→        $ingenieCustomer = $this->ingenieCustomerBuilder->build($contact);
112→
113→        $data = [];
114→
115→        /*
116→         * Send customer data to Ingenie
117→         *
118→         * Be careful :
119→         *  1/ a contact update on Redpill may be a customer create for Ingenie if contact wasn't already sent
120→         *  2/ even if we know the ingenieCustomerId, it could be deleted from Ingenie DB (deduplication, ...)
121→         */
122→        if (null !== $ingenieCustomerId) {
123→            try {
124→                $data = $this->ingenieApiRepository->updateCustomer($ingenieCustomer, $ingenieCustomerId);
125→            } catch (ApiClientException $e) {
126→                if (404 !== $e->getCode()) {
127→                    throw $e;
128→                }
129→
130→                /*
131→                 * When 404 Customer not found exception, the customer data will be resent as a creation with addCustomer.
132→                 */
133→                $this->logger->error(
134→                    sprintf('[%d] %s', $e->getCode(), $e->getMessage()),
135→                    ['ingenie_customer_id' => $ingenieCustomerId, 'contact_id' => $contact->getId()]
136→                );
137→                $ingenieCustomerId = null;
138→            }
139→        }
140→
141→        if (null === $ingenieCustomerId) {
142→            $data = $this->ingenieApiRepository->addCustomer($ingenieCustomer);
143→        }
144→
145→        if (!isset($data['id']) || empty($data['success'])) {
146→            throw new IngenieException(sprintf('Ingenie Api call does not return expected result : %s', serialize($data)));
147→        }
148→
149→        $newCustomerId = (int) $data['id'];
150→
151→        // Save ingenie customer id
152→        if ($ingenieCustomerId !== $newCustomerId) {
153→            $contact->addDatacustom([
154→                self::INGENIE_CONTACT_DATA_CUSTOM_KEY => $newCustomerId,
155→            ]);
156→            $this->entityManager->flush();
157→        }
158→
159→        return true;
160→    }
161→
162→    private function getIngenieCustomerId(Contact $contact): ?int
163→    {
164→        return $contact->getDatacustom()[self::INGENIE_CONTACT_DATA_CUSTOM_KEY] ?? null;
165→    }
166→
167→    /**
168→     * Is the contact able to be deleted into Ingenie Customer Api?
169→     */
170→    public function isDeletable(Contact $contact): bool
171→    {
172→        if (
173→            !$this->ingenieConfig->isApiEnabled()
174→            || !$this->ingenieResourceSpecification->isSatisfiedBy($contact)
175→        ) {
176→            return false;
177→        }
178→
179→        return (bool) $this->getIngenieCustomerId($contact);
180→    }
181→
182→    /**
183→     * Send delete contact to Ingenie Api customer.
184→     *
185→     * @throws IngenieException
186→     */
187→    public function deleteContact(Contact $contact): bool
188→    {
189→        // Get Ingenie Customer Id, if contact already sent
190→        $ingenieCustomerId = $this->getIngenieCustomerId($contact);
191→
192→        // Create Ingenie Customer payload from Redpill Contact entity
193→        $ingenieCustomer = $this->ingenieCustomerBuilder->build($contact, true);
194→
195→        $data = [];
196→        if (null !== $ingenieCustomerId) {
197→            $data = $this->ingenieApiRepository->updateCustomer($ingenieCustomer, $ingenieCustomerId);
198→        }
199→
200→        if (!isset($data['id']) || empty($data['success'])) {
201→            throw new IngenieException(sprintf('Ingenie Api call does not return expected result : %s', serialize($data)));
202→        }
203→
204→        return true;
205→    }
206→}
207→

