 19→/**
 20→ * Class IngenieApiRepository.
 21→ */
 22→class IngenieApiRepository
 23→{
 24→    protected ApiClientInterface $client;
 25→
 26→    private IngenieConfig $config;
 27→
 28→    public function __construct(
 29→        ApiClientInterface $ingenieApiClient,
 30→        IngenieConfig $config
 31→    ) {
 32→        $this->client = $ingenieApiClient;
 33→        $this->config = $config;
 34→    }
 35→
 36→    /**
 37→     * Ingenie Api get last customers call (from period).
 38→     *
 39→     * @return array<string, mixed>
 40→     */
 41→    public function getCustomers(string $updateFrom = '12h'): array
 42→    {
 43→        return $this->callCustomer('GET', '', ['query' => ['update_from' => $updateFrom]]);
 44→    }
 45→
 46→    /**
 47→     * Ingenie Api get one customer call.
 48→     *
 49→     * @return array<string, mixed>
 50→     */
 51→    public function getCustomer(int $id): array
 52→    {
 53→        return $this->callCustomer('GET', '/'.$id);
 54→    }
 55→
 56→    /**
 57→     * Ingenie Api add customer call.
 58→     *
 59→     * @return array<string, mixed>
 60→     */
