  8→use Eliberty\RedpillBundle\Exception\ApiConfigException;
  9→
 10→/**
 11→ * ApiConfigParameters decorate simple api parameters with values retrieve from ConfigManager.
 12→ */
 13→final class ApiConfigParameters implements ApiParametersInterface
 14→{
 15→    /**
 16→     * In async mode : ConfigManager Webinstance need to be initialized at messageHandler level,
 17→     * for exemple, with a message that implements the ConfigManagerInitInterface (messenger middleware).
 18→     */
 19→    private ConfigManager $cfgmanager;
 20→
 21→    private ApiParametersInterface $apiParameters;
 22→
 23→    /**
 24→     * @var array<string, array{0: string, 1?: string}> (paramKey => [ConfigManagerKey, ?JsonValueKey])
 25→     */
 26→    private array $apiConfigParams;
 27→
 28→    /**
 29→     * @param array<string, array{0: string, 1?: string}> $apiConfigParams (paramKey => [ConfigManagerKey, ?JsonValueKey])
 30→     */
 31→    public function __construct(
 32→        ConfigManager $cfgmanager,
 33→        ApiParametersInterface $apiParameters,
 34→        array $apiConfigParams
 35→    ) {
 36→        $this->cfgmanager    = $cfgmanager;
 37→        $this->apiParameters = $apiParameters;
 38→
 39→        // http-client client_options must be set only with ApiParameters, as http-client client_options set once at service factory level
 40→        if (isset($apiConfigParams['client_options'])) {
 41→            $apiConfigParams['options'] = $apiConfigParams['client_options'];
 42→            unset($apiConfigParams['client_options']);
 43→        }
 44→
 45→        // http-client base_uri must be set only with apiConfigParams, as http-client base_uri set once at service factory level
 46→        if (isset($apiConfigParams['base_uri'])) {
 47→            $apiConfigParams['main_uri'] = $apiConfigParams['base_uri'];   // base_uri could not be set into http-client as value change at runtime, so main_uri will be used for each call
 48→            unset($apiConfigParams['base_uri']);
 49→        }
 50→
 51→        $this->apiConfigParams = $apiConfigParams;
 52→    }
 53→
 54→    /**
 55→     * @return array<string, mixed>
 56→     */
 57→    public function getAll(): array
 58→    {
 59→        $apiConfigParameters = array_map(
 60→            fn ($apiConfigKey) => $this->getConfigValue($apiConfigKey),
 61→            $this->apiConfigParams
 62→        );
 63→
 64→        return array_merge($this->apiParameters->getAll(), $apiConfigParameters);
 65→    }
 66→
 67→    /**
 68→     * @return array|string|float|int|bool|\DateTime|null
 69→     */
 70→    public function get(string $key)
 71→    {
 72→        if (isset($this->apiConfigParams[$key])) {
 73→            return $this->getConfigValue($this->apiConfigParams[$key]);
 74→        }
 75→
 76→        return $this->apiParameters->get($key);
 77→    }
 78→
 79→    public function has(string $key): bool
 80→    {
 81→        return (bool) $this->get($key);
 82→    }
 83→
 84→    /**
 85→     * @param array{0: string, 1?: string} $configKey [key_path, json_sub_key]
 86→     *
 87→     * @return array|string|float|int|bool|\DateTime|null
 88→     */
 89→    private function getConfigValue(array $configKey, ?string $expectedType = null)
 90→    {
 91→        $configKeyStr = implode(', ', $configKey);
 92→
 93→        // 'key_path' is first item value
 94→        if (!isset($configKey[0])) {
 95→            throw new ApiConfigException(sprintf('ConfigKey[0] is required, found [%s]', $configKeyStr));
 96→        }
 97→
 98→        // Get value from config
 99→        $value = $this->cfgmanager->getJsonOption($configKey[0]);
100→
101→        // Get key into array value (json)
102→        if (\is_array($value) && $key = $configKey[1] ?? null) {
103→            if (!isset($value[$key])) {
104→                throw new ApiConfigException(sprintf('Unable to find key [%s] into config [%s]', $key, $configKeyStr));
105→            }
106→
107→            $value = $value[$key];
108→        }
109→
110→        if (null !== $expectedType && \is_callable('is_'.$expectedType)) {
111→            if (!\call_user_func('is_'.$expectedType, $value)) {
112→                throw new ApiConfigException(sprintf('Unexpected config type: Expect %s value for configKey[%s]', $expectedType, $configKeyStr));
113→            }
114→        }
115→
116→        return $value;
117→    }
118→}
