public function setToken(string $token): self
{
    if (null === $this->getHashKey()) {
        throw new ApiTokenException('Token hash key need to be set before storing token into redis cache');
    }

    // Line 44: Get TTL from token (remaining seconds)
    $ttl = $this->token->set($token)->getTtl();

    try {
        // Line 47: Store in Redis with TTL
        $this->cache->set($this->getHashKey(), $token, $ttl);
    } catch (InvalidArgumentException $e) {
        throw new ApiTokenException(...);
    }

    $this->logger->debug('Token store into redis cache', ['token' => $token]);
    return $this;
}
