**getToken() (Lines 62-81):**
```php
public function getToken(): ?string
{
    if (null === $this->getHashKey()) {
        throw new ApiTokenException('Token hash key need to be set before accessing token from redis cache');
    }

    try {
        // Line 69: Retrieve from Redis
        $cachedToken = $this->cache->get($this->getHashKey());
    } catch (InvalidArgumentException $e) {
        throw new ApiTokenException(...);
    }

    // Line 74: Check if token is still valid (not expired)
    if (\is_string($cachedToken) && !$this->token->set($cachedToken)->isExpired()) {
        $this->logger->debug('Valid token found in cache', ['token' => $cachedToken]);
        return $cachedToken;
    }

    return null;
}
